set-variable.value:
@{
        var h = context.Request.Headers.GetValueOrDefault("x-caller-app", "");
        if (!string.IsNullOrWhiteSpace(h)) { return h; }
        var sub = context.Subscription?.Name ?? "";
        if (!string.IsNullOrWhiteSpace(sub)) { return sub; }
        return "unattributed";
    }

@{
        var h = context.Request.Headers.GetValueOrDefault("x-environment", "");
        if (!string.IsNullOrWhiteSpace(h)) { return h; }
        return context.Subscription?.Name ?? "unknown";
    }
